export const 鎮宅牲畜 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：桿四＋星芒八射
    桿(0.7, 7.2, 1.0);
    桿(0.7, 7.2, 2.4);
    桿(0.7, 7.2, 3.6);
    桿(0.7, 5.4, 5.0);
    const 心 = [2.9, 7.4];
    圈(心[0], 心[1]);
    for (const t of [[1.6, 5.9], [3.0, 5.7], [4.1, 5.9], [5.0, 7.5], [4.0, 8.9],
        [2.7, 9.1], [1.3, 8.9], [0.9, 7.4]]) {
        連(心, [t[0], t[1]]);
        圈(t[0], t[1]);
    }
    // 厂桁
    線(p => p.M(X(0.9), Z(10.4)).L(X(7.2), Z(10.3)), 0.42);
    線(p => p.M(X(0.9), Z(10.45)).L(X(0.9), Z(11.3)));
    // 田箱
    線(p => p.M(X(1.3), Z(11.6)).L(X(1.3), Z(14.4)).L(X(6.8), Z(14.35))
        .L(X(6.8), Z(11.55)).L(X(1.25), Z(11.6)));
    線(p => p.M(X(4.05), Z(11.65)).L(X(4.0), Z(14.35)));
    線(p => p.M(X(1.4), Z(13.0)).L(X(6.7), Z(12.95)));
    // 弓迴脚（boustro二折）＋叉足
    線(p => p.M(X(1.4), Z(14.9)).L(X(5.6), Z(14.85))
        .C(X(6.1), Z(14.85), X(6.1), Z(15.8), X(5.6), Z(15.85))
        .L(X(2.2), Z(15.9)).C(X(1.7), Z(15.9), X(1.7), Z(16.85), X(2.2), Z(16.9))
        .L(X(5.7), Z(16.85)).C(X(6.2), Z(16.85), X(6.3), Z(17.4), X(6.2), Z(18.0)));
    線(p => p.M(X(2.0), Z(17.5)).C(X(1.7), Z(18.2), X(1.5), Z(18.8), X(1.4), Z(19.3)));
    線(p => p.M(X(3.9), Z(17.4)).L(X(3.9), Z(19.2)));
    線(p => p.M(X(6.2), Z(18.2)).C(X(6.3), Z(18.7), X(6.3), Z(19.0), X(6.25), Z(19.3)));
};
